export type PharmOpsTab = 'pending_dispense' | 'low_stock' | 'write_off' | 'inventory' | 'reports';

export interface PharmStockRow {
  inventory_id: number;
  drug_id: number;
  drug_name: string;
  lot_number: string;
  on_hand: number;
  expiration: string;
  expiry_status: 'expired' | 'expiring' | 'ok';
  /** INV-1 valuation: unit cost from the latest purchase (null = cost unknown), and lot value. */
  unit_cost?: number | null;
  value?: number | null;
  /** INV-4: per-drug average daily consumption (units/day) over the reorder window. */
  avg_per_day?: number;
  /** INV-7: supplier of the latest purchase; null/undefined = no supplier on record. */
  supplier_name?: string | null;
}

export interface PharmStockSummary {
  sku_count: number;
  expiring: number;
  expired: number;
  out_of_stock: number;
  at_reorder: number;
  /** INV-1 valuation totals (at cost). */
  total_value?: number;
  value_expiring?: number;
  value_expired?: number;
  wastage_rate_pct?: number;
  /** INV-6 expiry tiers: finer horizons than the 90-day `expiring` bucket above. */
  expiring_30?: number;
  expiring_60?: number;
  value_expiring_30?: number;
  value_expiring_60?: number;
}

export interface PharmStockBrowser {
  offset: number;
  has_more: boolean;
  /** Total matching lot count — only sent on the first page (offset 0); cache it across pages. */
  total?: number | null;
  summary: PharmStockSummary | null;
  currency_symbol?: string;
  generated_at: string;
  items: PharmStockRow[];
}

